static int Dtool_Traverse_FileReference(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  FileReference *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_FileReference, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_FileReference(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_FileReference._PyType && DtoolInstance_TYPE(self) == &Dtool_FileReference) {
    DtoolProxy_FileReference *proxy = (DtoolProxy_FileReference *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

